<style>
    .hobby-builder {
        display: grid;
        gap: 8px;
    }
    .hobby-controls {
        display: flex;
        flex-wrap: wrap;
        gap: 8px;
        align-items: center;
    }
    .hobby-controls select,
    .hobby-controls input {
        flex: 1 1 10em;
    }
    .hobby-tags {
        display: flex;
        flex-wrap: wrap;
        gap: 8px;
    }
    .hobby-chip {
        display: inline-flex;
        align-items: center;
        gap: 6px;
        border-radius: 999px;
        background: #f4f4f5;
        padding: 4px 10px;
    }
    .hobby-chip button {
        border: 0;
        background: transparent;
        cursor: pointer;
        font-size: 14px;
        line-height: 1;
    }
    .images-preview {
        display: flex;
        flex-wrap: wrap;
        gap: 10px;
        margin-top: 10px;
    }
    .image-thumb {
        position: relative;
        width: 100px;
        height: 100px;
    }
    .image-thumb img {
        width: 100%;
        height: 100%;
        object-fit: cover;
        border-radius: 8px;
        border: 1px solid #e5e7eb;
        display: block;
    }
    .remove-thumb {
        position: absolute;
        top: -7px;
        right: -7px;
        width: 22px;
        height: 22px;
        border: 0;
        border-radius: 999px;
        background: #ef4444;
        color: #fff;
        cursor: pointer;
        line-height: 1;
    }
</style>

<script>
    (function () {
        var form = document.querySelector("form[action='{{ url_for('posts.new_post') }}']");
        var tagsContainer = document.getElementById("hobby-tags");
        var emojiSelect = document.getElementById("hobby-emoji");
        var textInput = document.getElementById("hobby-text");
        var addButton = document.getElementById("add-hobby");
        var hiddenInput = document.getElementById("hobbies-input");
        var imageInput = document.getElementById("images-input");
        var previewContainer = document.getElementById("images-preview");
        var hobbies = [];
        var selectedFiles = [];
        var previewUrls = [];

        function syncHiddenInput() {
            hiddenInput.value = JSON.stringify(hobbies);
        }

        function renderHobbies() {
            tagsContainer.innerHTML = "";
            hobbies.forEach(function (item, index) {
                var chip = document.createElement("span");
                chip.className = "hobby-chip";

                var label = document.createElement("span");
                label.textContent = item.emoji + " " + item.text;
                chip.appendChild(label);

                var removeButton = document.createElement("button");
                removeButton.type = "button";
                removeButton.textContent = "✕";
                removeButton.setAttribute("aria-label", "删除兴趣");
                removeButton.addEventListener("click", function () {
                    hobbies.splice(index, 1);
                    syncHiddenInput();
                    renderHobbies();
                });
                chip.appendChild(removeButton);
                tagsContainer.appendChild(chip);
            });
        }

        function addHobby() {
            var emoji = emojiSelect.value;
            var text = (textInput.value || "").trim();
            if (!emoji || !text) {
                return;
            }
            hobbies.push({ emoji: emoji, text: text });
            textInput.value = "";
            syncHiddenInput();
            renderHobbies();
        }

        addButton.addEventListener("click", addHobby);
        textInput.addEventListener("keydown", function (event) {
            if (event.key === "Enter") {
                event.preventDefault();
                addHobby();
            }
        });

        function clearPreviewUrls() {
            for (var i = 0; i < previewUrls.length; i += 1) {
                URL.revokeObjectURL(previewUrls[i]);
            }
            previewUrls = [];
        }

        function renderImagePreview() {
            if (!previewContainer) {
                return;
            }

            clearPreviewUrls();
            previewContainer.innerHTML = "";

            selectedFiles.forEach(function (file, index) {
                var thumb = document.createElement("div");
                thumb.className = "image-thumb";

                var img = document.createElement("img");
                var previewUrl = URL.createObjectURL(file);
                previewUrls.push(previewUrl);
                img.src = previewUrl;
                img.alt = "图片预览";
                thumb.appendChild(img);

                var removeButton = document.createElement("button");
                removeButton.type = "button";
                removeButton.className = "remove-thumb";
                removeButton.textContent = "×";
                removeButton.setAttribute("aria-label", "删除图片");
                removeButton.addEventListener("click", function () {
                    selectedFiles.splice(index, 1);
                    renderImagePreview();
                });
                thumb.appendChild(removeButton);

                previewContainer.appendChild(thumb);
            });
        }

        if (imageInput) {
            imageInput.addEventListener("change", function () {
                var files = imageInput.files || [];
                for (var i = 0; i < files.length; i += 1) {
                    if (files[i].size > 5 * 1024 * 1024) {
                        alert("图片太大，请压缩后再上传");
                        continue;
                    }
                    if (selectedFiles.length >= 6) {
                        alert("最多上传6张");
                        break;
                    }
                    selectedFiles.push(files[i]);
                }

                imageInput.value = "";
                renderImagePreview();
            });
        }

        if (form) {
            form.addEventListener("submit", function (event) {
                event.preventDefault();

                var formData = new FormData(form);
                formData.delete("images");
                selectedFiles.forEach(function (file) {
                    formData.append("images", file);
                });

                fetch(form.action, {
                    method: "POST",
                    body: formData
                }).then(function (response) {
                    if (response.redirected) {
                        window.location.href = response.url;
                        return null;
                    }
                    return response.text();
                }).then(function (html) {
                    if (!html) {
                        return;
                    }
                    document.open();
                    document.write(html);
                    document.close();
                }).catch(function () {
                    alert("提交失败，请稍后重试");
                });
            });
        }

        try {
            var parsed = JSON.parse(hiddenInput.value || "[]");
            if (Array.isArray(parsed)) {
                hobbies = parsed.filter(function (item) {
                    return item && typeof item.emoji === "string" && typeof item.text === "string" && item.emoji && item.text;
                });
            }
        } catch (error) {
            hobbies = [];
        }
        syncHiddenInput();
        renderHobbies();
        renderImagePreview();
    })();
</script>
{% endblock %}

